INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('field3d_scenario_missing_devstatemeta_recognition', 'New field_3d scenario keys not recognised by deriveStateMeta → THE EYE mis-classifies reveal/hold/motion (false D7/D1p)', 'MAJOR', 'peter_parker:renderer_primitives', 'A new field_3d scenario''s per-state gauss_sphere keys were not recognised in maxRevealForField3dState/deriveHoldExpectations, so every state classified at the 1500ms default and false-failed D7/D1p.', 'When you add a field_3d scenario, add its per-state reveal/hold/motion recognition block to deriveStateMeta.ts in the SAME change as the renderer scenario.', 'manual', 'Run visual:eyes; the new scenario''s states must classify reveal_hold/interactive (not the 1500ms default) in the Reveal map line.', 'FIXED', ARRAY['gauss_law_sphere'], ARRAY['src/lib/validators/visual/deriveStateMeta.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('field3d_reveal_too_subtle_fails_d7', 'One-shot text/opacity reveal <0.1%/frame → D7 "animation died"', 'MAJOR', 'peter_parker:renderer_primitives', 'A subtle one-shot reveal (equation fade, small-element opacity) moves far less than 0.1% of the canvas, so D7 reads the tail as frozen.', 'A state''s reveal must either sustain continuous >=0.1%/frame motion OR be declared reveal_hold in deriveStateMeta so D7 relaxes.', 'js_eval', 'D7 dense-frame check: last 3 adjacent pairs must not all be <0.1% unless the state is reveal_hold/interactive.', 'FIXED', ARRAY['gauss_law_sphere'], ARRAY['src/lib/renderers/field_3d_renderer.ts', 'src/lib/validators/visual/deriveStateMeta.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('field3d_explorer_state_static_d1p', 'Explorer/slider state static under headless capture → D1p fail', 'MAJOR', 'peter_parker:renderer_primitives', 'A slider/interaction_complete state with no auto motion shows 0% pixel change under headless capture (the harness never drags).', 'Explorer states need an idle auto-sweep of their key param OR must be classified interactive (hold-intent) in deriveHoldExpectations.', 'js_eval', 'D1p first-vs-last frame; an explorer state must either be interactive (relaxed) or show motion via an idle sweep.', 'FIXED', ARRAY['gauss_law_sphere'], ARRAY['src/lib/renderers/field_3d_renderer.ts', 'src/lib/validators/visual/deriveStateMeta.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('field3d_time_gated_visual_invisible_in_slider_state', 'Time-gated visual invisible in a slider state (clock frozen at the opening frame)', 'MAJOR', 'peter_parker:renderer_primitives', 'A radius line gated on the state-clock emergence ramp stayed at length 0 in STATE_7 because the player freezes the clock at the opening frame and the user drives only the slider — the clock never reached the cue.', 'In slider/interactive states do NOT gate visuals on the state-clock emergence ramp; render at full immediately and track the slider value live.', 'manual', 'Open the explorer state without pressing play; drag the slider; the slider-driven visual must be present and track immediately.', 'FIXED', ARRAY['gauss_law_sphere'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('field3d_position_vector_foreshortened_3q_camera', 'Position/radius vector along a world axis reads diagonal "toward viewer" under a 3/4 camera', 'MODERATE', 'peter_parker:renderer_primitives', 'A radius vector pointed along a fixed world direction; under the 3/4 cameras it foreshortened into a diagonal pointing at the viewer instead of reading horizontal.', 'Position/radius vectors that must read horizontal should billboard to the camera-right vector each frame (screen-horizontal), not a fixed world direction.', 'manual', 'Inspect a 3/4-camera state; the radius line must read horizontal on screen, not a diagonal into the camera.', 'FIXED', ARRAY['gauss_law_sphere'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('field3d_overlay_line_occluded_over_geometry', 'Thin reference line washed out / occluded over a wireframe or translucent sphere', 'MODERATE', 'peter_parker:renderer_primitives', 'A thin white reference line rendered with depthTest on was occluded/low-contrast where it crossed the red shell + blue Gaussian wireframe.', 'Reference overlays that must read over busy 3D geometry use material.depthTest=false + a high renderOrder so they draw on top.', 'manual', 'Inspect the line where it crosses the sphere; it must read clearly, not be washed out by the geometry behind/over it.', 'FIXED', ARRAY['gauss_law_sphere'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('field3d_oneshot_element_vanishes_after_animation', 'One-shot animated element vanishes after the animation instead of holding its end pose', 'MAJOR', 'peter_parker:renderer_primitives', 'STATE_5 Gaussian sphere was animated by a one-shot shrink and then became invisible (opacity/scale fell to 0) instead of holding at its inside end pose.', 'One-shot animated elements must persist visible at their end pose after the animation completes; never let opacity/scale fall to 0 at completion.', 'manual', 'After the one-shot completes, the element must still be visible at its end pose in the frozen frame.', 'FIXED', ARRAY['gauss_law_sphere'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('field3d_radius_vector_tip_not_tracking_surface', 'Slider-driven radius line tip does not land on the live sphere surface', 'MODERATE', 'peter_parker:renderer_primitives', 'A vertical stagger pushed the r-line tip off the equator, so a length-r horizontal line no longer landed on the sphere''s silhouette edge as r changed.', 'A radius line that must touch a sphere uses length = the live radius and sits near the equator so its tip lands on the silhouette edge across the whole range.', 'manual', 'Drag the radius slider inside→outside; the line tip + tip-marker must stay on the sphere surface at every value.', 'FIXED', ARRAY['gauss_law_sphere'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('gsph_compare_offset_lt_object_radius', 'Side-by-side compare offset smaller than the object radius → groups overlap at centre', 'MAJOR', 'alex:json_author', 'STATE_4 compare offsets (±2.2) were smaller than the Gaussian sphere radius (2.4), so the left group crossed centre and crowded the right-side point charge.', 'Side-by-side group offsets must exceed each object''s visual extent; shrink the groups (compare_scale), widen the offsets, and pull the camera back so the halves are clearly separate.', 'manual', 'Inspect the compare state; the two groups must sit in clearly separate halves with empty space between, no overlap.', 'FIXED', ARRAY['gauss_law_sphere'], ARRAY['src/data/concepts/gauss_law_sphere.json', 'src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('field3d_label_sprite_overlap', 'Two 3D sprite labels placed too close overlap (Gaussian-sphere vs charged-shell top labels)', 'MODERATE', 'peter_parker:renderer_primitives', 'The "Gaussian sphere, radius r" and "charged shell, radius R" top labels are placed close enough that they slightly overlap.', 'Stack/space 3D sprite labels with adequate vertical separation so no two labels overlap.', 'manual', 'Inspect the top labels; no two label sprites should overlap.', 'OPEN', ARRAY['gauss_law_sphere'], ARRAY[]::text[], 'session_2026-06-25_field3d_diamonds', 'incident'),
('gauss_signed_pair_recolored_by_net_not_own_sign', 'STATE_5 signed pair: both inner charges recoloured by net sign (the +q should stay red)', 'MAJOR', 'peter_parker:renderer_primitives', 'Dragging the negative charge recoloured the ENTIRE inner charge pair by the net sign; each sphere should keep its own sign colour.', 'Colour each charge sphere and label by its OWN sign; only the field lines follow the net charge direction.', 'manual', 'Add a −q to a +q; the +q must stay red and the −q blue (only lines follow net).', 'FIXED', ARRAY['gauss_law'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('gauss_state1_readout_prespoils_epsilon', 'STATE_1 readout pre-spoils ε₀ before STATE_2 introduces it (sequencing / Rule 25)', 'MAJOR', 'peter_parker:renderer_primitives', 'STATE_1 readout showed the full "Φ = q_enc/ε₀" although STATE_2 is the first reveal of ε₀; the base readout wording was not gated on show_equation.', 'Gate readout wording on show_equation: STATE_1 shows "∝ q_enc" (no ε₀); STATE_2 first introduces "= q_enc/ε₀".', 'manual', 'STATE_1 readout must not contain ε₀; STATE_2 is the first state that shows it.', 'FIXED', ARRAY['gauss_law'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('gauss_state5_drag_neg_invisible_no_motion', 'STATE_5 narrated "−q grows" but the drag_neg tween was invisible (reads static)', 'MAJOR', 'peter_parker:renderer_primitives', 'The drag_neg_to mechanic changed only the readout + field, with no visible animation of the −q; the narrated change had no on-screen motion.', 'Every narrated change needs a visible animation. Replaced with an add_charge choreography (a 3rd enclosed −q + inward lines fade in).', 'manual', 'When the narration says a charge appears/grows, a charge sphere must visibly fade/grow in on screen.', 'FIXED', ARRAY['gauss_law'], ARRAY['src/lib/renderers/field_3d_renderer.ts', 'src/data/concepts/gauss_law.json'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('gauss_surface_morph_must_be_deterministic', 'Morphing/blob surface geometry must be deterministic (no per-frame randomness → flicker)', 'MODERATE', 'peter_parker:renderer_primitives', 'A per-frame-randomised blob/morph geometry would flicker and trip D1p/D7 pixel checks.', 'Compute morph/blob geometry once with a deterministic sin/cos basis; never randomise per frame.', 'manual', 'Two captures at the same sim-time must be pixel-identical for a static morph surface.', 'FIXED', ARRAY['gauss_law'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('gauss_outside_charge_flow_true_not_revealhold', 'Continuous field-line-flow state must be marked motion, not reveal_hold', 'MODERATE', 'peter_parker:renderer_primitives', 'A flow:true continuous-motion state, if mis-marked reveal_hold, would expect a static tail and could mis-gate.', 'States with flow:true declare continuous motion in deriveMotionExpectations (not reveal_hold); D5/D6/D7 then expect ongoing pixel motion.', 'manual', 'flow:true states classify as motion-expected, not reveal_hold.', 'FIXED', ARRAY['gauss_law'], ARRAY['src/lib/validators/visual/deriveStateMeta.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('flux_theta_anim_face_accumulate_reveal_hold', 'theta tilt sweep + face accumulation are one-shot reveals that hold → need reveal_hold pinning', 'MODERATE', 'peter_parker:renderer_primitives', 'The open-surface theta_anim tilt and closed-surface face accumulation complete then hold still; without reveal_hold, D7/D1p false-fail the static tail.', 'Pin maxReveal past the theta_anim/accumulate payoff and mark these states reveal_hold in deriveStateMeta.', 'manual', 'electric_flux sweep/accumulate states classify reveal_hold and pin past their payoff.', 'FIXED', ARRAY['electric_flux'], ARRAY['src/lib/validators/visual/deriveStateMeta.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('flux_epsilon0_cutline_inversion_guard', 'electric_flux must NOT show ε₀ (net flux ∝ q_enc only); gauss_law deliberately inverts this', 'MODERATE', 'alex:json_author', 'electric_flux ends at "net Φ ∝ q_enc" in arbitrary units (no ε₀); gauss_law is the concept that flips the label to "= q_enc/ε₀". Mixing them breaks the teaching cut-line.', 'Keep the cut-line: electric_flux stays ∝ q_enc (no ε₀); only gauss_law writes ε₀ on-canvas from STATE_2.', 'manual', 'electric_flux on-canvas text contains no ε₀; gauss_law does from STATE_2.', 'FIXED', ARRAY['electric_flux', 'gauss_law'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('cdist_state6_chunks_occluded_by_transparency', 'STATE_6 dq chunks dimmed/hidden by transparency render-sort behind the solid', 'MODERATE', 'peter_parker:renderer_primitives', 'dq chunks positioned behind the semi-transparent solid were dimmed/reordered by transparency render-sort.', 'Render accumulation chunks opaque (transparent:false) and position them in front of the body (z > the solid''s front face).', 'manual', 'All six STATE_6 chunks visible and crisp on the front face, none dimmed/occluded.', 'FIXED', ARRAY['charge_distribution'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('cdist_state6_chunks_arrows_undersized', 'STATE_6 dq chunks + dE arrows too small/dim → accumulation aha unreadable', 'MODERATE', 'peter_parker:renderer_primitives', 'Chunks (0.26) and dE arrows (0.9) were too small/dim for the founder visual review.', 'Size accumulation chunks ~0.40 with emissive ~0.9 and dE arrows ~1.2 length with bright heads so the aha reads.', 'manual', 'STATE_6 chunks + dE arrows are clearly legible at review resolution.', 'FIXED', ARRAY['charge_distribution'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('cdist_morph_accumulate_reveal_hold', 'rod→sheet→solid morph + dq accumulation are one-shot reveals that hold → need reveal_hold pinning', 'MODERATE', 'peter_parker:renderer_primitives', 'The morph cross-fade and dq accumulation complete then hold; without reveal_hold pinning, D7/D1p false-fail the static tail.', 'Pin maxReveal past the morph/accumulate payoff and mark these states reveal_hold.', 'manual', 'charge_distribution morph/accumulate states classify reveal_hold.', 'FIXED', ARRAY['charge_distribution'], ARRAY['src/lib/validators/visual/deriveStateMeta.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('solenoid_dropped_prediction_pauses_x4', 'Four prediction pause_after_ms dropped in the JSON handoff (cross-agent regression)', 'MAJOR', 'alex:json_author', 'json_author cloned the electric_flux JSON (which has no predictions) and dropped 4 of 5 prediction pause_after_ms; Gate 3c does not run on field_3d so nothing caught it.', 'When porting a field_3d JSON, carry every pause_after_ms from the physics block; field_3d DOES consume pause_after_ms via deriveStateMeta.', 'manual', 'Each prediction sentence retains its pause_after_ms per the physics block.', 'FIXED', ARRAY['magnetic_field_solenoid'], ARRAY['src/data/concepts/magnetic_field_solenoid.json'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('solenoid_state2_bare_coil_no_orientation_4s', 'STATE_2 bare coil for ~4s before B-circles appear (no orientation cue)', 'MODERATE', 'alex:json_author', 'per_turn_field_circles.reveal_at_ms ~4000 left an unlabeled bare coil during the state-entry window.', 'Every non-intro state needs an orientation cue within the first reveal window (~1.5s); lower late reveal_at_ms.', 'manual', 'STATE_2 shows a meaningful cue within ~1.5s of entry, not a bare coil for 4s.', 'FIXED', ARRAY['magnetic_field_solenoid'], ARRAY['src/data/concepts/magnetic_field_solenoid.json'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('solenoid_state3_annotation_orphaned_from_referent', 'STATE_3 labels render at t=0 while their referent arrows reveal 6–8.5s later', 'MAJOR', 'peter_parker:renderer_primitives', 'scene_composition annotations have no reveal timing and render at t=0, but the arrows they describe reveal at 6000/8500ms — the label sits with no referent.', 'Gate annotations to appear WITH their referent arrows (verify the field_3d renderer consumes annotation reveal timing first).', 'manual', 'A label and the visual it describes appear together, not 6s apart.', 'OPEN', ARRAY['magnetic_field_solenoid'], ARRAY[]::text[], 'session_2026-06-25_field3d_diamonds', 'incident'),
('solenoid_state4_outside_fade_narrated_not_shown', 'STATE_4 "outside ≈ 0" is narrated but no cancellation/fade is shown', 'MAJOR', 'peter_parker:renderer_primitives', 'STATE_4 narrates that the field outside is ~0 but there is no fade/cancellation visual; only sparse static lines.', 'Add an outside-field-fade/cancellation primitive keyed to reveal_at_ms so the "outside ≈ 0" claim is shown, not just said.', 'manual', 'STATE_4 visibly fades/cancels the outside field; not narration-only.', 'OPEN', ARRAY['magnetic_field_solenoid'], ARRAY[]::text[], 'session_2026-06-25_field3d_diamonds', 'incident'),
('solenoid_state5_gesture_sequencing_absent', 'STATE_5 grip cross-fade narrated but the right-hand does not animate (no gesture sequencing)', 'MAJOR', 'peter_parker:renderer_primitives', 'extras.right_hand applies at state-enter only; there is no delayed/triggered gesture-reveal, so the wire-grip→solenoid-grip cross-fade is a static overlay.', 'Add a gesture-sequencing primitive so the grip animation lands after the prediction pause (reveal after the question).', 'manual', 'STATE_5 animates the grip transition on cue, not a static hand.', 'OPEN', ARRAY['magnetic_field_solenoid'], ARRAY[]::text[], 'session_2026-06-25_field3d_diamonds', 'incident'),
('solenoid_state7_hand_flip_unimplemented', 'STATE_7 narrates a hand-flip but has no right_hand object / motion primitive', 'MAJOR', 'alex:json_author', 'STATE_7 narration promises "watch the hand flip as current reverses" but the state instantiates no hand and no flip motion.', 'Instantiate the hand + flip animation in STATE_7, or do not narrate a visual that is not drawn.', 'manual', 'STATE_7 shows the promised hand-flip when current reverses.', 'OPEN', ARRAY['magnetic_field_solenoid'], ARRAY[]::text[], 'session_2026-06-25_field3d_diamonds', 'incident'),
('solenoid_focal_primitive_on_title_not_physics', 'focal_primitive_id points at the title label on 7/8 states, not the physics element', 'MODERATE', 'alex:json_author', 'focal_primitive_id was placed on the top-centre title because the physics-bearing field_3d elements live outside scene_composition.', 'Point focal_primitive_id at the physics-bearing element per state (or confirm field_3d uses it at all before gating).', 'manual', 'Each state''s focal cue lands on the physics element, not the heading.', 'OPEN', ARRAY['magnetic_field_solenoid'], ARRAY[]::text[], 'session_2026-06-25_field3d_diamonds', 'incident'),
('solenoid_per_turn_circles_reveal_hold', 'per_turn_field_circles / coil-morph reveals are one-shot then hold → reveal_hold pinning', 'MODERATE', 'peter_parker:renderer_primitives', 'The per-turn field-circle reveal and wire→coil morph complete then hold; without reveal_hold pinning D7/D1p false-fail the tail.', 'Pin maxReveal past per_turn_field_circles / wire_to_coil_morph payoff and mark reveal_hold.', 'manual', 'solenoid reveal states classify reveal_hold.', 'FIXED', ARRAY['magnetic_field_solenoid'], ARRAY['src/lib/validators/visual/deriveStateMeta.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('rhr_state5_glyph_force_desync_ignored_per_state_ambient', 'STATE_5 ⊗/⊙ glyph and F derived from different B fields → F points opposite to RHR', 'CRITICAL', 'peter_parker:renderer_primitives', 'The frame read the global ambient_field and ignored STATE_5''s per-state override [0,0,-1]; the glyph char came from the global field while F came from the override (or vice versa), so they desynced.', 'Honour the per-state ambient_field override and derive the glyph char from the SAME bEff used to compute F, so glyph and F can never desync.', 'manual', 'In every RHR state the ⊗/⊙ glyph sign matches the F direction the right-hand rule gives.', 'FIXED', ARRAY['magnetic_force_direction_right_hand_rule'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('rhr_direction_only_hard_cutline', 'Direction-only scenario must never show magnitude / r=mv/qB / period / zero-length F stub', 'MAJOR', 'alex:json_author', 'A direction-of-F=qv×B concept must teach direction only; showing a magnitude number, orbit radius, period, or a zero-length F at v∥B is off-scope/misleading.', 'Hide F when v∥B (no zero stub); never render a Newton/Tesla magnitude, r=mv/qB, or period T in the direction concept.', 'manual', 'No magnitude/r/T anywhere; F hidden at v∥B.', 'FIXED', ARRAY['magnetic_force_direction_right_hand_rule'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('rhr_reveal_beats_reveal_hold', 'RHR reveal gestures (f_appear/show_hand/camera_orbit/glyph_toggle/ghost_f) are one-shot then hold', 'MODERATE', 'peter_parker:renderer_primitives', 'The RHR reveal beats complete then hold; without reveal_hold pinning D7/D1p false-fail the static tail.', 'Pin maxReveal past each RHR beat and mark non-slider RHR states reveal_hold.', 'manual', 'RHR reveal states classify reveal_hold.', 'FIXED', ARRAY['magnetic_force_direction_right_hand_rule'], ARRAY['src/lib/validators/visual/deriveStateMeta.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('nowork_state1_trajectory_mode_mismatch_caption', 'STATE_1 trajectory_mode "straight" while the caption says "round and round"', 'MODERATE', 'alex:json_author', 'STATE_1 set trajectory_mode "straight" but narrates circular motion; the visual contradicts the words.', 'trajectory_mode must match the narrated motion (set "circle" when the narration says it goes round).', 'manual', 'STATE_1 shows circular motion matching the caption.', 'FIXED', ARRAY['magnetic_force_perpendicular_no_work'], ARRAY['src/data/concepts/magnetic_force_perpendicular_no_work.json'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('nowork_state5_meters_overlap_caption', 'STATE_5 split-screen work/speed meters overlap the bottom-left caption', 'MODERATE', 'peter_parker:renderer_primitives', 'Both meters were at the bottom-left, competing with the caption for space.', 'Place the two comparison meters top-left/top-right above the caption; keep the bottom for the caption.', 'manual', 'STATE_5 meters and caption do not overlap.', 'FIXED', ARRAY['magnetic_force_perpendicular_no_work'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('nowork_generic_legend_on_every_state_rule24', 'Generic B-field legend (Red=N/Blue=S/Lines=B) drawn on every state (Rule 24 violation)', 'MODERATE', 'peter_parker:renderer_primitives', 'The renderer drew the generic field legend by default on every field_3d state, adding prose-y chrome that violates the silent-visual rule.', 'Suppress the generic legend per scenario (as charge_distribution/electric_flux/gauss_law do); keep on-canvas to labels/equations.', 'manual', 'No generic legend on the scenario''s states.', 'FIXED', ARRAY['magnetic_force_perpendicular_no_work'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('nowork_hard_cutline_no_magnitude', 'No-work scenario must never show force magnitude / r=mv/qB / period; F is direction-only', 'MAJOR', 'alex:json_author', 'The direction+no-work concept must not show a force magnitude, orbit radius, or period; F is a fixed-length centripetal glyph hidden at v∥B; B changes orbit tightness only.', 'Enforce the cut-line in the frame: speed meter ties to KE (not force), W pinned 0 (asserted not integrated), never a magnitude number.', 'manual', 'No magnitude/r/T; F fixed-length; W=0 asserted on the magnetic side.', 'FIXED', ARRAY['magnetic_force_perpendicular_no_work'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('nowork_speed_work_meter_flat_vs_rising_contract', '|v| meter must hold flat + W pinned 0 on the magnetic side; both rise on the electric side', 'MODERATE', 'peter_parker:renderer_primitives', 'The teaching contract is: magnetic side keeps |v| constant (W=0); electric side speeds up (W>0). A meter that drifts on the magnetic side breaks the proof.', 'Magnetic side: speed meter dead-flat, W pinned 0 (asserted). Electric side: both rise as F·v does work.', 'manual', 'Magnetic |v|/W flat/0; electric |v|/W rising.', 'FIXED', ARRAY['magnetic_force_perpendicular_no_work'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('field3d_visible_elements_substring_match_greedy', 'visible_elements substring match is greedy ("wire" matches fl_wire_*/arr_wire_*) → premature blooming', 'MODERATE', 'alex:json_author', 'applyState''s visible_elements matcher uses substring indexOf, so a token like "wire" matches wire_main AND the field-line/arrow groups, blooming the field too early.', 'Use specific element tokens (wire_main, curr_arr) in visible_elements; the renderer exact/separator-aware match is the proper fix (deferred).', 'manual', 'STATE_1 shows only the intended elements, not everything matching a substring.', 'FIXED', ARRAY['magnetic_field_wire', 'magnetic_field_concept_B'], ARRAY['src/data/concepts/magnetic_field_wire.json'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('field3d_orbit_spiral_on_radius_ramp', 'Orbit trail accumulates into a spiral with drifting centre + stray X during a radius ramp', 'CRITICAL', 'peter_parker:renderer_primitives', 'During a radius ramp (ghost_compare/sliders) the orbit trajectory was accumulated frame-by-frame; at varying R the points no longer form a closed circle → broken spiral, drifting centre, self-crossing X.', 'When R can change within a state, draw a COMPLETE ring each frame at the current R about a FIXED origin (never accumulate trail); capture the ghost at the true reveal-time R; THE EYE must read DENSE ramp frames, not only the frozen end.', 'manual', 'During a radius ramp, every dense frame shows a clean closed ring at a fixed centre — no spiral, no stray X.', 'FIXED', ARRAY['circular_motion_charge_in_uniform_B'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('field3d_array_form_show_sliders_not_marked_interactive', 'Array-form show_sliders not recognised as interactive → static sandbox false-fails D1p', 'MODERATE', 'peter_parker:visual_validator', 'deriveHoldExpectations marks a field_3d state interactive only when show_sliders===true (strict boolean), but field_3d allows show_sliders as a string array of slider names; an array-form sandbox false-failed the static-image check.', 'Treat array-form show_sliders and advance_mode==="interaction_complete" as interactive in the field_3d branch (match the PCPL branch).', 'manual', 'A field_3d state with array-form show_sliders classifies interactive, not strict.', 'FIXED', ARRAY['electric_dipole_in_field'], ARRAY['src/data/concepts/electric_dipole_in_field.json', 'src/lib/validators/visual/deriveStateMeta.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('field3d_i2_tts_synced_math_invisible_to_capture', 'TTS-synced SET_MATH formulas invisible to headless capture → I2 false-fail', 'MODERATE', 'peter_parker:visual_validator', 'The validator never plays TTS, so formulas revealed at TTS timestamps via SET_MATH were absent from captured frames.', 'Replay the per-sentence SET_MATH schedule and snapshot one equation-panel frame per formula for the vision gate.', 'manual', 'I2 frames include the TTS-revealed formulas.', 'FIXED', ARRAY['magnetic_force_moving_charge'], ARRAY['src/lib/validators/visual/screenshotter.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('crossagent_jsonauthor_drops_pause_after_ms_cloning_electric_flux', 'json_author drops pause_after_ms when cloning electric_flux (cross-agent regression pattern)', 'MAJOR', 'alex:json_author', 'Cloning electric_flux (which has no predictions, hence no pause_after_ms) as a template drops the physics block''s prediction pauses; Gate 3c does not run on field_3d so it is not caught automatically.', 'When porting any field_3d JSON, explicitly carry every pause_after_ms from the physics block; field_3d consumes them via deriveStateMeta.', 'manual', 'Every prediction sentence retains its pause_after_ms after the JSON port.', 'FIXED', ARRAY['gauss_law', 'magnetic_field_solenoid', 'gauss_law_sphere'], ARRAY['src/data/concepts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('gate3c_does_not_run_on_field3d_use_gate15', 'Gate 3c (Socratic-reveal) never fires on field_3d (no teaching_method) → use Gate 15', 'MAJOR', 'peter_parker:visual_validator', 'Gate 3c only fires on states with teaching_method:"narrative_socratic", a PCPL-only field absent on every field_3d concept; so it structurally never runs on diamonds.', 'Gate 15 (Pass-2 four-question) is the cognitive-flow gate for field_3d; audit pause-before-resolution + motion-before-words there.', 'manual', 'field_3d concepts are audited by Gate 15, not Gate 3c.', 'FIXED', ARRAY['gauss_law', 'gauss_law_sphere', 'magnetic_field_solenoid', 'magnetic_force_direction_right_hand_rule', 'magnetic_force_perpendicular_no_work', 'charge_distribution', 'electric_flux'], ARRAY['.agents/quality_auditor/CLAUDE.md'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('rule29_size_pulse_emphasis_drift', 'Emphasis via size-pulse (vector bulge / hand scale / point-P scale) violates Rule 29', 'MAJOR', 'peter_parker:renderer_primitives', 'Attention/TTS emphasis used a size-pulse (vector 70% bulge, right-hand 4% scale, highlighted point 15% scale) instead of brightness.', 'Emphasis = brightness only (applyGlowEmphasis / emissive shimmer); a length changes ONLY when a real physical magnitude changes (e.g. tauThrob).', 'manual', 'No time-based scale/zoom pulse for emphasis anywhere in field_3d.', 'FIXED', ARRAY['gauss_law', 'gauss_law_sphere', 'charge_distribution', 'magnetic_force_direction_right_hand_rule', 'torque_on_current_loop_in_field'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('field3d_routing_downgrade_to_mechanics2d_in_strict_bypass', 'field_3d concepts silently downgraded to mechanics_2d in the strict-engines bypass', 'CRITICAL', 'peter_parker:runtime_generation', 'The strict-engines bypass only routed PCPL vs mechanics_2d; field_3d concepts fell into the else and were assembled as p5.js mechanics_2d, silently downgrading the Three.js diamonds.', 'Route any concept with a field_3d_config block via assembleField3DHtml (engine threejs) in the strict-engines bypass.', 'manual', 'A field_3d concept served through the bypass returns Three.js HTML (PM markers), not M2_* mechanics_2d.', 'FIXED', ARRAY['gauss_law', 'electric_flux', 'charge_distribution', 'magnetic_field_wire', 'magnetic_field_solenoid', 'magnetic_field_concept_B'], ARRAY['src/lib/aiSimulationGenerator.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('classifier_capital_B_suffix_truncation', 'Intent classifier regex truncates a trailing capital _B → misclassification', 'MAJOR', 'peter_parker:runtime_generation', 'extractAdvertisedConcepts regex ^([a-z][a-z0-9_]*) only matched lowercase after the first char, stripping a trailing capital _B.', 'Use ^([a-z][A-Za-z0-9_]*) so concept ids with a capital suffix (…_B) classify correctly.', 'manual', 'A query for a _B-suffixed concept classifies to the full id, not a truncated one.', 'FIXED', ARRAY['magnetic_field_concept_B', 'circular_motion_charge_in_uniform_B'], ARRAY['src/lib/intentClassifier.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
('eye_e2_e3_storyboard_metadata_not_plumbed', 'E2/E3 (focal/anchor) false-fail because storyboard metadata not passed to the vision gate', 'MODERATE', 'peter_parker:visual_validator', 'E2 (focal_primitive_id) and E3 (real_world_anchor) false-failed because the smoke context never sourced them from the concept JSON.', 'Source real_world_anchor + focal_primitive_ids + tts_visual_bindings from the concept JSON into VisionGateContext.', 'manual', 'E2/E3 read the JSON metadata and stop false-failing when it is present.', 'FIXED', ARRAY['magnetic_force_moving_charge'], ARRAY['src/lib/validators/visual/visionGate.ts'], 'session_2026-06-25_field3d_diamonds', 'incident'),
