('teach_concrete_before_abstract_compare', 'When a derived result equals a simpler known one, show the simple case ALONE first, then the complex one beside it', 'MODERATE', 'alex:architect', 'Founder: the shell-field derivation lands far better when the point charge is explained alone first, then the shell appears beside it for comparison (concrete → abstract).', 'For a "this equals that simpler thing" aha, stage it: simple case alone (left empty), THEN introduce the complex case beside it, THEN highlight that the formulas match.', 'manual', 'Architect: the compare state explains the simple object first, alone, before the complex one appears.', 'OPEN', ARRAY['gauss_law_sphere'], ARRAY[]::text[], 'session_2026-06-25_field3d_diamonds', 'directive'),
('teach_reveal_synced_to_narration', 'Author timed reveals so the visual beat lands as the narration introduces it (no early pop / no static wait)', 'MODERATE', 'alex:physics_author', 'Founder: a reveal that fires long before the narrating sentence pops in early then sits static; it reads as unexplained.', 'Tune each reveal at_ms to the cumulative narration pacing of the sentence that introduces it (Rule 26 keeps motion on the sim clock; tune the times to the script).', 'manual', 'Physics-author: each timed reveal lands within ~1s of its introducing narration beat.', 'OPEN', ARRAY['gauss_law_sphere', 'magnetic_field_solenoid'], ARRAY[]::text[], 'session_2026-06-25_field3d_diamonds', 'directive'),
('teach_coordinate_sim_with_graph', 'When a state has both a 3D sim and a graph, drive ONE live parameter that moves BOTH together', 'MODERATE', 'alex:architect', 'Founder: a static E-vs-r curve teaches less than a live coordinated sweep where the sphere radius and the graph dot move in lockstep.', 'For sim+graph states, drive a single live parameter that animates both the 3D scene and a tracking dot on the graph together; never ship a static curve.', 'manual', 'Architect: the sim+graph state moves both in lockstep off one parameter.', 'OPEN', ARRAY['gauss_law_sphere'], ARRAY[]::text[], 'session_2026-06-25_field3d_diamonds', 'directive'),
('teach_show_quantity_live_when_named', 'When the narration names a quantity, draw/grow its visual live at that moment', 'MODERATE', 'alex:physics_author', 'Founder: showing the radius line grow live exactly when the narration says "radius r" maps the word to the picture.', 'When narration first names a quantity (radius r, the field E…), reveal/grow its visual live on that beat so the word maps to the picture.', 'manual', 'Physics-author: each named quantity has a visual that appears/grows on its naming beat.', 'OPEN', ARRAY['gauss_law_sphere'], ARRAY[]::text[], 'session_2026-06-25_field3d_diamonds', 'directive'),
('teach_distinct_reference_lines_for_two_radii', 'When two radii appear (R shell vs r field-point), draw both as distinct, clearly-labelled lines', 'MODERATE', 'alex:architect', 'Founder: students conflate the shell radius R with the field-point distance r; two distinct labelled lines from the centre prevent this.', 'When two radii are in play, draw both as separate, clearly-labelled reference lines (e.g. R to the shell, r to the field point) so they are never conflated.', 'manual', 'Architect: distinct labelled R and r reference lines wherever both appear.', 'OPEN', ARRAY['gauss_law_sphere'], ARRAY[]::text[], 'session_2026-06-25_field3d_diamonds', 'directive'),
('teach_visual_must_match_narration', 'The visual must match what is said (trajectory matches "round and round"; "outside ≈ 0" must be SHOWN)', 'MAJOR', 'alex:architect', 'Founder/THE EYE: states narrated circular motion while drawing straight drift, or narrated "outside ≈ 0" with nothing fading — the picture contradicted or omitted the words.', 'Every claim the narration makes must be visible: motion mode matches the described motion, and any "becomes zero / cancels / grows" is shown, not just said.', 'manual', 'Architect: walk the script; every narrated claim has a matching on-screen visual.', 'OPEN', ARRAY['magnetic_force_perpendicular_no_work', 'magnetic_field_solenoid'], ARRAY[]::text[], 'session_2026-06-25_field3d_diamonds', 'directive'),
('teach_do_not_prespoil_a_later_reveal', 'Do not show a quantity/formula before the state that introduces it (ε₀ at STATE_2, not STATE_1)', 'MODERATE', 'alex:architect', 'gauss_law STATE_1 pre-showed ε₀ before STATE_2 was meant to introduce it, spoiling the sequenced reveal.', 'Gate on-canvas quantities/formulas to the state that teaches them; earlier states use the simpler form (∝) and do not pre-spoil the later reveal.', 'manual', 'Architect: no state shows a quantity earlier than the state that introduces it.', 'OPEN', ARRAY['gauss_law'], ARRAY[]::text[], 'session_2026-06-25_field3d_diamonds', 'directive'),
